import{_ as t,o as r,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Onboarding Guide","description":"","frontmatter":{"title":"Onboarding Guide","slug":"onboarding-guide"},"headers":[],"relativePath":"marketer-hub/onboarding-guide.md","filePath":"marketer-hub/onboarding-guide.md"}'),o={name:"marketer-hub/onboarding-guide.md"};function i(s,e,d,h,l,p){return r(),a("div",null,[...e[0]||(e[0]=[n('<p><em>[Image: Illustration of web and email communication with highlighted elements for user interaction.]</em>.png)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Welcome to Branch!</p><p>This guide will help you:</p><ul><li>Set up your Branch account.</li><li>Integrate Branch into your marketing stack.</li><li>Measure and optimize your mobile growth efforts.</li></ul><h2 id="introduction-to-branch" tabindex="-1">Introduction to Branch <a class="header-anchor" href="#introduction-to-branch" aria-label="Permalink to &quot;Introduction to Branch&quot;">​</a></h2><p>The Branch Growth Platform is a powerful <strong>deep linking</strong>, <strong>attribution</strong>, and <strong>mobile growth</strong> solutionthat helps track user journeys across platforms, optimize marketing campaigns, and improve your users’ experience.</p><p>With Branch, you can:</p><ul><li><strong>Accurately track</strong> user acquisition, re-engagement, and conversion across paid, organic, and owned digital channels.</li><li><strong>Enhance user experience</strong> with deep links that take users directly to in-app content.</li><li><strong>Optimize marketing campaigns</strong> with detailed attribution data.</li></ul><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>Before starting the steps in this guide, you must <a href="https://monster-factory-web.app.link/e/dashboard" target="_blank" rel="noreferrer">sign up</a> for the Branch Growth Platform.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>You must add a payment method to your account within 30 days of creating it. Learn more on our <a href="./how-billing-works.html">billing page</a>.</p></div><h4 id="branch-packages" tabindex="-1">Branch packages <a class="header-anchor" href="#branch-packages" aria-label="Permalink to &quot;Branch packages&quot;">​</a></h4><p>Some features are included in the Branch Growth Platform, while others require you to sign up for them. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more.</p><h4 id="activation" tabindex="-1">Activation <a class="header-anchor" href="#activation" aria-label="Permalink to &quot;Activation&quot;">​</a></h4><p>If you’re looking for onboarding information for our <a href="./packaging.html#activation-product">Activation</a> product, check out our dedicated <a href="./activation-onboarding-guide.html">Activation Onboarding Guide</a>.</p><h2 id="get-started-with-branch" tabindex="-1">Get started with Branch <a class="header-anchor" href="#get-started-with-branch" aria-label="Permalink to &quot;Get started with Branch&quot;">​</a></h2><p>Complete the steps in this guide to start launching campaigns powered by Branch’s deep linking and attribution solutions.</p><p>Some steps will require help from developers or other members of your team — this guide will point out when that is the case.</p><p>Branch Integration Roadmap</p><h3 id="step-1-branch-account" tabindex="-1">Step 1: Branch account <a class="header-anchor" href="#step-1-branch-account" aria-label="Permalink to &quot;Step 1: Branch account&quot;">​</a></h3><p>Set important values like default timezone, link domain, and global attribution window setting in Branch.</p><p><strong>After you complete this step</strong>, you will be ready to start integrating Branch SDKs.</p><details><summary>Expand to view tasks</summary><p>In the context of this guide, the Account Admin is the primary owner and user of your Branch account.</p><table tabindex="0"><thead><tr><th>Task</th><th>Owner</th><th>Description</th><th>Time estimate*</th></tr></thead><tbody><tr><td>Add relevant team members</td><td>Account Admin</td><td><a href="https://help.branch.io/docs/manage-users-permissions" target="_blank" rel="noreferrer">Add users</a> with relevant permissions to your Branch Dashboard on the <a href="https://monster-factory-web.app.link/e/teamtab" target="_blank" rel="noreferrer">Team tab</a>.</td><td>15 minutes</td></tr><tr><td>Set default timezone</td><td>Account Admin</td><td><a href="https://help.branch.io/v1/docs/profile-settings#dashboard-analytics-time-zone" target="_blank" rel="noreferrer">Set your timezone</a> in the <a href="https://monster-factory-web.app.link/e/profiletab" target="_blank" rel="noreferrer">Profile tab</a> of the Branch Dashboard.</td><td>1 minute</td></tr><tr><td>Set link domain</td><td>Account Admin, Marketing Team</td><td>Your link domain determines how your Branch Links will appear across platforms. <a href="https://help.branch.io/v1/docs/advanced-settings-configuration#link-domain" target="_blank" rel="noreferrer">Set up your link domain</a> in the <a href="https://monster-factory-web.app.link/e/generaltab" target="_blank" rel="noreferrer">General tab</a> of the <strong>App Settings</strong> page of the Branch Dashboard.</td><td>30 minutes</td></tr><tr><td>Set global attribution window setting</td><td>Marketing Team</td><td>Attribution windows determine the attribution period for installs and other down-funnel events, starting from the time of the click. <a href="https://help.branch.io/v1/docs/attribution-windows-link-settings#configure-attribution-windows" target="_blank" rel="noreferrer">Set your global attribution window setting</a> in the <a href="https://monster-factory-web.app.link/e/attributiontab" target="_blank" rel="noreferrer">Attribution tab</a> of the <strong>App Settings</strong> page of the Branch Dashboard.</td><td>15 minutes</td></tr><tr><td>Decide on routing logic</td><td>Mobile Developers</td><td>Branch is built to work with your existing deep linking logic. The Branch SDK captures and shares data when someone opens your app with a Branch Link. Developers will need to decide <strong>which keys to read</strong>, <strong>and how to pass them</strong> to your routing flow. Use our <a href="https://help.branch.io/v1/docs/deep-link-data-options#deep-link-data-key-values" target="_blank" rel="noreferrer">Deep Link Data Options guide</a> to understand the different keys Branch allows you to pass to your links (alternatively, you can also pass custom key-value pairs).</td><td>2 hours</td></tr><tr><td>Finalize list of events to track</td><td>Marketing Team</td><td>Event tracking helps you enable attribution for down-funnel events. Remember to track the events that make the most sense to you in terms of attribution. Use our <a href="https://help.branch.io/developers-hub/docs/track-branch-events#types-of-branch-events" target="_blank" rel="noreferrer">Branch Event guide</a> to understand the different types of Branch Events in more detail.</td><td>2 hours</td></tr><tr><td>Set up link configuration</td><td>Mobile Developers</td><td><a href="./configure-default-link-behaviors.html">Configure link behavior</a> on the <a href="https://monster-factory-web.app.link/e/generaltab" target="_blank" rel="noreferrer">General tab</a> of the <strong>App Settings</strong> page of the Branch Dashboard.</td><td>1 hour</td></tr></tbody></table></details><h3 id="step-2-branch-mobile-sdks" tabindex="-1">Step 2: Branch mobile SDKs <a class="header-anchor" href="#step-2-branch-mobile-sdks" aria-label="Permalink to &quot;Step 2: Branch mobile SDKs&quot;">​</a></h3><p>Set the foundation for enabling deep linking into your app using Branch Links, and start tracking Branch Events.</p><p><strong>After you complete this step</strong>, you can start using Branch Links in your apps, as well as analyze events and usage in the Branch Dashboard.</p><details><summary>Expand to view tasks</summary><p>Your mobile development team will own all of the tasks in this step.</p><table tabindex="0"><thead><tr><th>Task</th><th>Owner</th><th>Description</th><th>Time Estimate*</th></tr></thead><tbody><tr><td>Integrate Branch mobile SDKs</td><td>Mobile Developers</td><td>Use the following guides to implement the relevant Branch SDKs into your apps: - <a href="https://help.branch.io/developers-hub/docs/ios-basic-integration" target="_blank" rel="noreferrer">iOS</a> - <a href="https://help.branch.io/developers-hub/docs/android-basic-integration" target="_blank" rel="noreferrer">Android</a> - <a href="https://help.branch.io/developers-hub/docs/react-native-index" target="_blank" rel="noreferrer">React Native</a> - <a href="https://help.branch.io/developers-hub/docs/flutter-sdk-index" target="_blank" rel="noreferrer">Flutter</a> - <a href="https://help.branch.io/developers-hub/docs/plugins-overview" target="_blank" rel="noreferrer">Other plugins and wrappers</a></td><td>8 hours</td></tr><tr><td>Test integration</td><td>Mobile Developers</td><td>Test and validate that your Branch integration is working as expected using the guides below: - <a href="https://help.branch.io/developers-hub/docs/ios-testing" target="_blank" rel="noreferrer">iOS SDK Testing</a> - <a href="https://help.branch.io/developers-hub/docs/android-testing" target="_blank" rel="noreferrer">Android SDK Testing</a> View <a href="https://help.branch.io/developers-hub/docs/native-sdks-overview" target="_blank" rel="noreferrer">testing documentation for Branch&#39;s native SDKs</a> in Developers Hub.</td><td>16 hours</td></tr><tr><td>Set up in-app routing</td><td>Mobile Developers</td><td>Using data from the Branch SDK initialization callback, <a href="https://help.branch.io/developers-hub/docs/in-app-routing" target="_blank" rel="noreferrer">route the user</a> to the correct content within your app.</td><td>24 hours</td></tr><tr><td>Track events</td><td>Mobile Developers</td><td>Developers should track Branch Events based on the app&#39;s functionality, as well as the events list chosen by the marketing team in Step 1. Code samples demonstrating how to track Branch Events are available in our <a href="https://help.branch.io/developers-hub/docs/track-branch-events#event-tracking" target="_blank" rel="noreferrer">event tracking guide</a>. We also recommend you review the conceptual content related to Branch Events in the <a href="https://help.branch.io/developers-hub/docs/track-branch-events#overview" target="_blank" rel="noreferrer">Overview section</a> of the guide.</td><td>16 hours</td></tr><tr><td>Release app</td><td>Mobile Developers</td><td>Release the latest versions of your apps with the relevant Branch SDKs integrated to start using Branch Links and other Branch functionality.</td><td>1 hour</td></tr></tbody></table><p><strong>Troubleshooting</strong>:</p><p>Use the guides below if you need troubleshooting assistance during Branch SDK implementation:</p><ul><li><a href="https://help.branch.io/developers-hub/docs/ios-troubleshooting" target="_blank" rel="noreferrer">iOS Troubleshooting</a></li><li><a href="https://help.branch.io/developers-hub/docs/android-troubleshooting" target="_blank" rel="noreferrer">Android Troubleshooting</a></li></ul><p><strong>Learn more</strong>:</p><ul><li><a href="https://monster-factory-web.app.link/e/university1" target="_blank" rel="noreferrer">Link Creation &amp; Management Made Easy</a></li><li><a href="https://monster-factory-web.app.link/e/university2" target="_blank" rel="noreferrer">Engagement: Short Links</a></li><li><a href="https://monster-factory-web.app.link/e/university10" target="_blank" rel="noreferrer">Seamless Branding: Custom QR Codes</a></li></ul></details><h3 id="step-3-branch-web-sdk-and-journeys" tabindex="-1">Step 3: Branch Web SDK and Journeys <a class="header-anchor" href="#step-3-branch-web-sdk-and-journeys" aria-label="Permalink to &quot;Step 3: Branch Web SDK and Journeys&quot;">​</a></h3><p>Track and attribute events on your website using the Web SDK, and set up <a href="https://help.branch.io/docs/journeys" target="_blank" rel="noreferrer">Journeys</a> banners.</p><p><strong>After you complete this step</strong>, you can start tracking seamless web-to-app user experiences and conversion analytics.</p><details><summary>Expand to view tasks</summary><p>Journeys are smart, customizable <strong>web-to-app banners</strong> that drive seamless user transitions, increasing engagement and conversions.</p><h4 id="tracking-and-attribution" tabindex="-1">Tracking and attribution: <a class="header-anchor" href="#tracking-and-attribution" aria-label="Permalink to &quot;Tracking and attribution:&quot;">​</a></h4><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time Estimate*</strong></th></tr></thead><tbody><tr><td>Implement Web SDK</td><td>Web Developers</td><td>Implement the Web SDK on your website using the <a href="https://help.branch.io/developers-hub/docs/web-basic-integration" target="_blank" rel="noreferrer">Web Basic Integration guide</a>. We recommend integrating the Web SDK on every page of your website for full coverage of web tracking and banner rendering on every page. Alternatively, set up the Web SDK using a tag manager: - <a href="https://help.branch.io/developers-hub/docs/gtm-web" target="_blank" rel="noreferrer">Google Tag Manager</a> - <a href="https://help.branch.io/developers-hub/docs/adobe-launch-web-plugin" target="_blank" rel="noreferrer">Adobe Launch</a></td><td>30 minutes</td></tr><tr><td>Test Web SDK integration</td><td>Web Developers</td><td>Test your Web SDK integration using the <a href="https://help.branch.io/developers-hub/docs/web-testing" target="_blank" rel="noreferrer">Web Testing guide</a>.</td><td>1 hour</td></tr><tr><td>Track Branch Events</td><td>Web Developers</td><td>Track web events with Branch based on the critical functionality of your website, as well as the events list decided on by your marketing team. To implement tracking Branch Events with the Web SDK, visit the <a href="https://help.branch.io/developers-hub/docs/web-advanced-features#event-tracking" target="_blank" rel="noreferrer">Web SDK Advanced Features page</a>.</td><td>2 hours</td></tr><tr><td>Deploy website</td><td>Web Developers</td><td>Deploy your website with the Web SDK implementation to production. After this, you can start using Branch Links and understanding attribution data across web.</td><td>30 minutes</td></tr></tbody></table><h4 id="journeys" tabindex="-1"><strong>Journeys:</strong> <a class="header-anchor" href="#journeys" aria-label="Permalink to &quot;**Journeys:**&quot;">​</a></h4><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time Estimate*</strong></th></tr></thead><tbody><tr><td>Enable Journeys</td><td>Marketing Team, Web Team</td><td>Drive web-to-app conversions using smart banners by turning on Branch Journeys. You can create a new Journey by going to the Journeys page of the Branch Dashboard and clicking the <strong>Create New Journey</strong> button. Find more information in our detailed <a href="./create-journey-banner-or-interstitial.html">Journeys guide</a>.</td><td>15 minutes per Journey</td></tr><tr><td>Configure Journeys creatives</td><td>Marketing Team, Web Team</td><td>Optimize Branch Journeys creatives with <a href="./advanced-journeys-configuration.html">advanced configuration</a>, <a href="./advanced-journeys-ui-html-css.html">HTML &amp; CSS customization</a>, and <a href="./desktop-journeys.html">Desktop Journeys</a> for seamless cross-device experiences.</td><td>30 minutes</td></tr></tbody></table><p><strong>Learn more:</strong></p><ul><li><a href="https://monster-factory-web.app.link/e/university3" target="_blank" rel="noreferrer">Engagement: Journeys</a></li><li><a href="https://monster-factory-web.app.link/e/university4" target="_blank" rel="noreferrer">Crack the Code: Perfect Your Banners</a></li><li><a href="https://monster-factory.app.link/university5" target="_blank" rel="noreferrer">Cross-Platform Banners: The Desktop-to-App Journey</a></li><li><a href="https://monster-factory-web.app.link/e/university6" target="_blank" rel="noreferrer">Dynamic Banner Templates</a></li></ul><p>Access to Journeys requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p></details><h3 id="step-4-ads" tabindex="-1">Step 4: Ads <a class="header-anchor" href="#step-4-ads" aria-label="Permalink to &quot;Step 4: Ads&quot;">​</a></h3><p>Configure your ad partner integrations and start tracking paid media performance effectively.</p><p><strong>After you complete this step</strong>, you can enable attribution tracking and analyze campaign performance across ad networks in the Branch Dashboard.</p><details><summary>Expand to view tasks</summary><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time Estimate*</strong></th></tr></thead><tbody><tr><td>Integrate Branch with ad networks</td><td>Product Manager, Marketing Team, Agency</td><td>Learn more about the different types of ad partners and how to integrate them with Branch using the guides below. <strong>Self-attributing network (SAN)</strong>: - <a href="./google-ads.html">Google</a> - <a href="./facebook-ads-overview.html">Facebook/Meta</a> - <a href="./apple-search-ads.html">Apple Ads</a> - <a href="./snap.html">Snap</a> - <a href="./twitter-ads.html">Twitter</a> - <a href="./tiktok-for-business.html">TikTok For Business</a> - <a href="./yahoo-ads.html">Yahoo</a> <strong>Non-SAN</strong>: - <a href="./ad-partner-integration-guide.html">Affiliate Partners</a> - <a href="./ad-links.html">Create Ad Links</a> SANs report conversions directly to Branch, while non-SANs require Branch Ad Links to track clicks and impressions. Set up these integrations using the <a href="https://branch.dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Partner Management tool</a> in the Ads section of the Branch Dashboard.</td><td>15 minutes per ad network</td></tr><tr><td>Configure SKAdNetwork for iOS</td><td>Product Manager</td><td><a href="./enable-skadnetwork.html">Configure SKAdNetwork (SKAN)</a> for iOS attribution under Apple&#39;s privacy framework. In conjunction, <a href="./predictive-aggregate-measurement.html">enable Predictive Aggregate Measurement (PAM)</a> with the flip of a switch for accurate and privacy-preserving campaign tracking without using IDFA.</td><td>3 hours</td></tr><tr><td>Test ad partner integrations</td><td>Product Manager, Marketing Team, Agency</td><td>Validate and test the ad partner integrations you set using the <a href="./testing-ads-campaign-setup.html">Test Ads Campaign Setup guide</a>.</td><td>2 hours</td></tr><tr><td>Configure advanced ad capabilities</td><td>Product Manager, Marketing Team</td><td>Maximize ad impact with <a href="./engagement-builder.html">Engagement Builder</a> for retargeting, <a href="./fraud.html">Fraud Protection</a> to secure spend, and <a href="./roi-hub.html">ROI Hub</a> for a complete view of your campaign spend and ROI.</td><td>2 hours</td></tr></tbody></table><p><strong>Note:</strong></p><ul><li><p>Always use Ad Links for paid campaigns to maximize attribution accuracy and campaign insights. They support $3p values, custom macros, and dynamic campaign data for seamless reporting. While Ad Links are required for affiliate partners, their usage in SAN campaigns depends on the ad partner and campaign type. Refer to the <a href="https://help.branch.io/using-branch/docs/self-attributing-networks-sans#san-ad-campaigns-support" target="_blank" rel="noreferrer">SANs Overview guide</a> for SAN ad campaigns support.</p></li><li><p>To ensure accurate tracking and avoid discrepancies, it&#39;s essential to match the <a href="https://help.branch.io/using-branch/docs/enable-google-app-campaigns#4-configure-attribution-windows" target="_blank" rel="noreferrer">attribution windows</a> and the <a href="https://help.branch.io/using-branch/docs/profile-settings#section-dashboard-analytics-time-zone" target="_blank" rel="noreferrer">timezone</a> between Branch and your ad partners. This alignment helps provide consistent and reliable conversion data across all platforms. If not matched, the defaults from the app level are loaded automatically.</p></li></ul><p><strong>Learn more:</strong></p><ul><li><a href="https://monster-factory-web.app.link/e/university7" target="_blank" rel="noreferrer">Performance: Ad Links</a></li><li><a href="https://monster-factory-web.app.link/e/university8" target="_blank" rel="noreferrer">ROI Hub: Unlock Cost Data Insights</a></li></ul></details><h3 id="step-5-email" tabindex="-1">Step 5: Email <a class="header-anchor" href="#step-5-email" aria-label="Permalink to &quot;Step 5: Email&quot;">​</a></h3><p>Configure your Email Service Provider integrations.</p><p><strong>After you complete this step</strong>, you can use Branch Links in your email campaigns, ensure proper deep linking functionality, and track user engagement and conversions in the Branch Dashboard.</p><details><summary>Expand to view tasks</summary><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time Estimate*</strong></th></tr></thead><tbody><tr><td>Verify your ESP integrates with Branch</td><td>Marketing Team, Email Service Provider, CRM Team</td><td>Search for your ESP in the <a href="./supported-email-partners.html">email partners list</a>.</td><td>15 minutes</td></tr><tr><td>Configure click tracking domain (CTD)</td><td>Marketing Team, Email Service Provider, CRM Team</td><td>If possible, create a new click tracking domain. The majority of ESP integrations require that you update the DNS record for your CTD to include a CNAME (alias) record that points to Branch’s <code>thirdparty.bnc.lt</code> domain. Use the steps in our <a href="./email-integration-guide.html#dns-cname-configuration">Email Integration guide</a> to complete this configuration.</td><td>1 hour</td></tr><tr><td>Add CTD to Associated Domains and <code>Info.plist</code></td><td>iOS Developers</td><td>In order for iOS to open the app when an email link is clicked, your CTD will need to be added to the Associated Domains and <code>Info.plist</code>, the steps for which can be found in our <a href="https://help.branch.io/developers-hub/docs/ios-basic-integration#3-configure-associated-domains" target="_blank" rel="noreferrer">iOS Basic Integration guide</a>.</td><td>5 minutes</td></tr><tr><td>Add code to handle web-only links</td><td>Mobile Developers</td><td>Some links in your emails may be marked as web-only, so you will want to have code to route the user back to the web destination once the app opens and parses the URL. Use the sample apps below to see examples of this: - <a href="https://github.com/BranchMetrics/Branch-Example-Deep-Linking-Branchster-iOS/blob/master/BranchMonsterFactory/AppDelegate.m" target="_blank" rel="noreferrer">iOS</a> - <a href="https://github.com/BranchMetrics/Branch-Example-Deep-Linking-Branchster-Android/blob/master/app/src/main/java/io/branch/branchster/SplashActivity.java" target="_blank" rel="noreferrer">Android</a></td><td>2 hours</td></tr><tr><td>Enable ESP integration</td><td>Marketing Team, Project Manager, Technical Team (Developers)</td><td>In the Branch Dashboard, navigate to the <a href="https://monster-factory-web.app.link/e/managertab" target="_blank" rel="noreferrer">Manager tab</a> of the Email section. Enable your ESP integrations here. On the Validate &amp; Test page resolve any warnings or errors to ensure everything’s working correctly.</td><td>15 minutes</td></tr><tr><td>Flag links in email templates</td><td>Marketing Team, CRM Team</td><td>Many integrations require that you flag links in the email template before you send it. Use the <a href="./email-integration-guide.html#send-emails-with-flagged-links">Email Integration guide</a> and click the <strong>Help Me Flag My ESP’s Links</strong> button. Search for your ESP to find the specific steps for your integration.</td><td>10 minutes per email template</td></tr><tr><td>Validate integration</td><td>CRM Team, QA Team</td><td><a href="https://help.branch.io/v1/docs/data-integration-implementation-guide#3-retrieve-keyscredentials-from-your-partner" target="_blank" rel="noreferrer">Generate a test link</a> and/or send a test email to an internal audience to ensure the Branch Links in your email work as expected.</td><td>3 hours</td></tr></tbody></table><p><strong>Note:</strong></p><p>For deep link data like <code>$canonical_url</code> to be passed, you will need to:</p><ol><li>Go to Validate &amp; Test in the Manager tab</li><li>Click Deep linking is set up for email</li><li>Enable the first 3 check boxes</li><li>Add <code>$canonical_url</code> to the translate option</li></ol><p><strong>Learn more:</strong></p><ul><li><a href="https://monster-factory-web.app.link/e/university9" target="_blank" rel="noreferrer">Engagement: Email</a></li></ul></details><h3 id="step-6-data-feeds" tabindex="-1">Step 6: Data Feeds <a class="header-anchor" href="#step-6-data-feeds" aria-label="Permalink to &quot;Step 6: Data Feeds&quot;">​</a></h3><p>Integrate third-party analytics providers and configure data exports.</p><p><strong>After you complete this step</strong>, you can enable automated data exports to your preferred third-party destination for in-depth analysis and reporting.</p><details><summary>Expand to view tasks</summary><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time Estimate*</strong></th></tr></thead><tbody><tr><td>Verify analytics partner integration exists</td><td>Data Team, Project Manager</td><td>Make sure Branch integrates with your chosen analytics partner(s) by searching for them in the <a href="./supported-data-integration-partners.html">Data Integration Partners list</a>.</td><td>15 minutes</td></tr><tr><td>Enable analytics partner integration(s)</td><td>Data Team</td><td>To enable your analytics partner data integration(s), use the <strong>Data Integrations</strong> tab under <strong>Data Feeds</strong> in the Branch Dashboard. You can also find detailed steps in the <a href="./data-integration-implementation-guide.html">Data Integration Implementation guide</a>.</td><td>15 minutes per partner</td></tr><tr><td>Pass partner metadata to Branch SDK</td><td>Mobile Developers</td><td>You will need to pass specific partner data to the Branch SDK before initialization. To see what data you need to pass, visit the <a href="./supported-data-integration-partners.html">Data Integration Partners list</a> and search for the data integration partner. Click on it to view the details of that data integration partner.</td><td>1 hour</td></tr><tr><td>Verify events are being sent</td><td>Data Team, QA Team, Mobile Developers</td><td>Ensure that Branch Events are appearing on the Branch Dashboard in the Liveview tool. In the <a href="https://monster-factory-web.app.link/e/webhooks" target="_blank" rel="noreferrer">Webhook Records tab</a>, filter by the Webhook Partner Key of your analytics partner (specified in the Branch documentation for that ad partner integration). Please note that this tool has a delay of a few minutes, and you may need to click the <strong>Update Session</strong> button to see data populate. The specific filters for each analytics partners are included on their individual documentation pages, for example: - <a href="https://help.branch.io/partners-portal/docs/adobe-analytics#5-verify-data-sent" target="_blank" rel="noreferrer">Adobe Analytics</a> - <a href="https://help.branch.io/partners-portal/docs/google-analytics-4#4-verify-data-sent" target="_blank" rel="noreferrer">Google Analytics</a> - <a href="https://help.branch.io/partners-portal/docs/mixpanel#4-verify-data-sent" target="_blank" rel="noreferrer">Mixpanel</a> Finally, check that you are seeing the Branch Events on the analytics partner’s dashboard.</td><td>2 hours</td></tr><tr><td>Move Branch data into storage of choice</td><td>Data Team</td><td>Use Branch’s APIs to export your data to various different storage options. For example, the Scheduled Log Exports API lets you send your data to your own AWS or GCP account, store your data in a Branch-owned S3 bucket, or have the data emailed to you on a regular cadence. <strong>Log level:</strong> - <a href="https://help.branch.io/apidocs/daily-exports-api" target="_blank" rel="noreferrer">Daily Export API</a> - <a href="https://help.branch.io/apidocs/custom-exports-api" target="_blank" rel="noreferrer">Custom Export API</a> - <a href="https://help.branch.io/apidocs/scheduled-log-exports-api" target="_blank" rel="noreferrer">Scheduled Log Exports API</a> <strong>Aggregate:</strong> - <a href="http://help.branch.io/apidocs/aggregate-api" target="_blank" rel="noreferrer">Aggregate API</a> - <a href="https://help.branch.io/apidocs/query-api" target="_blank" rel="noreferrer">Query API</a> - <a href="https://help.branch.io/apidocs/cross-events-export-api" target="_blank" rel="noreferrer">Cross-Events Export API</a> - <a href="https://help.branch.io/apidocs/unified-analytics-export" target="_blank" rel="noreferrer">Unified Analytics Export</a> To learn more about API access, please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a>,</td><td>3 hours</td></tr></tbody></table></details><h3 id="step-7-seo-app-attribution-deep-linking-from-search-ads" tabindex="-1">Step 7: SEO App Attribution &amp; deep linking from search ads <a class="header-anchor" href="#step-7-seo-app-attribution-deep-linking-from-search-ads" aria-label="Permalink to &quot;Step 7: SEO App Attribution &amp; deep linking from search ads&quot;">​</a></h3><p>Analyze users coming from organic search, including the down-funnel actions they perform within the app.</p><p><strong>After you complete this step</strong>, you can start attributing app conversions from organic search traffic and getting visibility into app engagement driven by search engines.</p><details><summary>Expand to view tasks</summary><table tabindex="0"><thead><tr><th><strong>Task</strong></th><th><strong>Owner</strong></th><th><strong>Description</strong></th><th><strong>Time Estimate*</strong></th></tr></thead><tbody><tr><td>Configure Universal Links and App Links</td><td>Technical Team (Developers)</td><td>Enable <strong>your own business domain</strong> (this is where your website lives, for example <code>www.yourcompany.com</code> ) as Universal Links and App Links. This is required for Google Ads, SEO, and any marketing channels that don&#39;t support third-party links like Branch Links. This is separate from your Branch Link domain configuration. Setting up Universal Links and App Links ensures that your app is opened directly when users visit your domain from search engines, ads, or other channels. Use the guides below to enable Universal and App Links: - <a href="https://help.branch.io/developers-hub/docs/ios-universal-links" target="_blank" rel="noreferrer">Universal Links</a> - <a href="https://help.branch.io/developers-hub/docs/android-app-links" target="_blank" rel="noreferrer">App Links</a></td><td>1 hour</td></tr><tr><td>Add SEO domains</td><td>Technical Team (Developers), Marketing Team</td><td>Enter your top-level domain (SEO domain) in the <strong>Configuration</strong> tab of the SEO page of the Branch Dashboard to register SEO attribution using Branch. For more detailed steps, follow the <a href="./seo-app-attribution.html">SEO App Attribution guide</a>.</td><td>5 minutes</td></tr><tr><td>Test integration</td><td>Technical Team (Developers)</td><td>Test the overall integration using the testing section of the <a href="https://help.branch.io/v1/docs/seo-app-attribution#testing-troubleshooting" target="_blank" rel="noreferrer">SEO App Attribution guide</a>.</td><td>1 hour</td></tr></tbody></table></details><h2 id="additional-support" tabindex="-1">Additional support <a class="header-anchor" href="#additional-support" aria-label="Permalink to &quot;Additional support&quot;">​</a></h2><p>Branch offers several ways to connect with expert guidance as you learn how to use all the powerful features of the Branch Growth Platform.</p><h3 id="live-trainings" tabindex="-1">Live trainings <a class="header-anchor" href="#live-trainings" aria-label="Permalink to &quot;Live trainings&quot;">​</a></h3><p>For continued learning, <a href="https://branchu.app.link/e/XvE0493DFVb" target="_blank" rel="noreferrer">Branch University</a> offers live, expert-led <a href="https://monster-factory-web.app.link/e/universitylive" target="_blank" rel="noreferrer">training sessions</a> designed to help you master our products, sharpen your skills, and gain hands-on experience. These sessions provide an opportunity to ask questions directly to our trainers, ensuring you get the most out of the Branch Growth Platform.</p><h3 id="professional-services" tabindex="-1">Professional Services <a class="header-anchor" href="#professional-services" aria-label="Permalink to &quot;Professional Services&quot;">​</a></h3><p>For deeper technical support, QA testing, or custom solutions, our Professional Services team is here to help. We offer dedicated workshops to better understand your goals, assist with setup, and provide guidance through go-live and beyond.</p><p>To learn more, please reach out to your Branch point of contact or <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to request scoping.</p><p>*<em>The time estimates provided for each task are approximate and intended as general guidance. Actual completion times may vary depending on factors such as your team’s prior experience with Branch and the complexity of your existing app logic.</em></p>',56)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
